WITH RECURSIVE L AS(SELECT employee_id,employee_name,manager_id,salary,1 level FROM Employees WHERE manager_id IS NULL UNION ALL SELECT e.employee_id,e.employee_name,e.manager_id,e.salary,l.level+1 FROM Employees e JOIN L l ON e.manager_id=l.employee_id),D AS(SELECT employee_id manager,employee_id emp FROM Employees UNION ALL SELECT d.manager,e.employee_id FROM D d JOIN Employees e ON e.manager_id=d.emp)SELECT l.employee_id,l.employee_name,l.level,COUNT(d.emp)-1 team_size,SUM(e.salary) budget FROM L l JOIN D d ON l.employee_id=d.manager JOIN Employees e ON d.emp=e.employee_id GROUP BY l.employee_id,l.employee_name,l.level ORDER BY l.level,budget DESC,l.employee_name;